import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** Represents a webhook delivery attempt. */
export interface WebhookDelivery {
  url: string;
  payload: WebhookPayloadBody;
  statusCode?: number;
  deliveredAt: Date;
  metadata?: Record<string, unknown>;
}

/** The JSON body sent to the webhook URL. */
export interface WebhookPayloadBody {
  event: string;
  recipient: string;
  subject: string;
  body: string;
  priority: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/** Configuration for the WebhookAdapter. */
export interface WebhookAdapterConfig {
  /** The URL to POST webhook payloads to. */
  url: string;
  /** Optional custom headers to include with the request. */
  headers?: Record<string, string>;
  /** Optional custom transport function (for testing or custom HTTP clients). */
  transport?: (url: string, options: WebhookRequestOptions) => Promise<WebhookResponse>;
}

/** Options passed to the transport function. */
export interface WebhookRequestOptions {
  method: 'POST';
  headers: Record<string, string>;
  body: string;
}

/** Response from the transport function. */
export interface WebhookResponse {
  ok: boolean;
  status: number;
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private deliveries: WebhookDelivery[] = [];
  private config: WebhookAdapterConfig;

  constructor(config: WebhookAdapterConfig) {
    this.config = config;
  }

  /**
   * Format the notification payload into a webhook JSON body.
   */
  formatPayload(payload: NotificationPayload): WebhookPayloadBody {
    return {
      event: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      priority: payload.priority,
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Validate that the configured URL is a valid HTTP(S) URL.
   */
  static validateUrl(url: string): boolean {
    try {
      const parsed = new URL(url);
      return parsed.protocol === 'http:' || parsed.protocol === 'https:';
    } catch {
      return false;
    }
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // 1. Validate URL
      if (!WebhookAdapter.validateUrl(this.config.url)) {
        const msg = `Invalid webhook URL: ${this.config.url}`;
        this.logger.warn(msg);
        return { success: false, error: msg };
      }

      // 2. Format payload
      const webhookBody = this.formatPayload(payload);
      const bodyJson = JSON.stringify(webhookBody);

      // 3. Build request options
      const headers: Record<string, string> = {
        'Content-Type': 'application/json',
        ...this.config.headers,
      };

      const requestOptions: WebhookRequestOptions = {
        method: 'POST',
        headers,
        body: bodyJson,
      };

      // 4. Send via transport
      let statusCode: number | undefined;
      if (this.config.transport) {
        const response = await this.config.transport(this.config.url, requestOptions);
        statusCode = response.status;
        if (!response.ok) {
          const msg = `Webhook request failed with status ${response.status}`;
          this.logger.warn(msg);
          // Still record the delivery attempt
          this.deliveries.push({
            url: this.config.url,
            payload: webhookBody,
            statusCode,
            deliveredAt: new Date(),
            metadata: payload.metadata,
          });
          return { success: false, error: msg };
        }
      }

      // 5. Record successful delivery
      const delivery: WebhookDelivery = {
        url: this.config.url,
        payload: webhookBody,
        statusCode: statusCode ?? 200,
        deliveredAt: new Date(),
        metadata: payload.metadata,
      };
      this.deliveries.push(delivery);

      this.logger.info(`Webhook delivered to ${this.config.url}: ${payload.type}`);
      return { success: true };
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to deliver webhook to ${this.config.url}: ${message}`);
      return { success: false, error: message };
    }
  }

  /** Get all delivery records. Useful for testing. */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /** Clear delivery records. Useful for testing. */
  clearDeliveries(): void {
    this.deliveries = [];
  }
}

